const canvas=document.querySelector('#networkCanvas'), ctx=canvas.getContext('2d'), wrap=document.querySelector('#canvasWrap');
const state={rotX:-.08,rotY:.08,zoom:1,drag:false,lastX:0,lastY:0,startX:0,startY:0,hover:null,selected:'abalos',filter:'all',query:'',caseFocus:null};
let dpr=1, projected=[];

function resize(){dpr=Math.min(window.devicePixelRatio||1,2);const r=wrap.getBoundingClientRect();canvas.width=r.width*dpr;canvas.height=r.height*dpr;canvas.style.width=r.width+'px';canvas.style.height=r.height+'px';ctx.setTransform(dpr,0,0,dpr,0,0);draw()}
function transform(n){const cy=Math.cos(state.rotY),sy=Math.sin(state.rotY),cx=Math.cos(state.rotX),sx=Math.sin(state.rotX);let x=n.x*cy-n.z*sy,z=n.x*sy+n.z*cy,y=n.y*cx-z*sx;z=n.y*sx+z*cx;const perspective=720/(720+z);return{...n,sx:wrap.clientWidth/2+x*perspective*state.zoom,sy:wrap.clientHeight/2+y*perspective*state.zoom,scale:perspective*state.zoom,depth:z}}
function searchableText(n){return[n.name,n.subtitle,n.role,n.charge,n.chargeNote,n.phase,n.phaseNote,n.moneyLabel,n.moneyNote].filter(Boolean).join(' ').toLowerCase()}
function visible(n){if(state.filter!=='all'&&n.status!==state.filter)return false;if(state.query&&!searchableText(n).includes(state.query))return false;if(state.caseFocus&&n.id!==state.caseFocus&&!(n.caseIds||[]).includes(state.caseFocus))return false;return true}
function activeIds(){if(!state.selected)return new Set();const selected=nodes.find(node=>node.id===state.selected),ids=new Set([state.selected]);if(!selected)return ids;if(selected.kind==='case'){actors.filter(actor=>actor.caseIds.includes(selected.id)).forEach(actor=>ids.add(actor.id));return ids}selected.caseIds.forEach(caseId=>ids.add(caseId));actors.filter(actor=>actor.id!==selected.id&&actor.caseIds.some(caseId=>selected.caseIds.includes(caseId))).forEach(actor=>ids.add(actor.id));links.forEach(link=>{if(link.a===selected.id)ids.add(link.b);if(link.b===selected.id)ids.add(link.a)});return ids}
function draw(){ctx.clearRect(0,0,wrap.clientWidth,wrap.clientHeight);projected=nodes.filter(visible).map(transform).sort((a,b)=>a.depth-b.depth);const pmap=new Map(projected.map(p=>[p.id,p])),active=activeIds();links.forEach(l=>{const a=pmap.get(l.a),b=pmap.get(l.b);if(!a||!b)return;const hi=state.selected&&active.has(l.a)&&active.has(l.b);ctx.beginPath();ctx.moveTo(a.sx,a.sy);ctx.lineTo(b.sx,b.sy);ctx.strokeStyle=hi?'rgba(127,231,242,.82)':'rgba(87,116,132,.2)';ctx.lineWidth=hi?1.45:.7;ctx.shadowColor=hi?'#7fe7f2':'transparent';ctx.shadowBlur=hi?9:0;ctx.stroke();ctx.shadowBlur=0});projected.forEach(n=>drawNode(n,active));document.querySelector('#emptyState').hidden=projected.length>0}
function drawNode(n,active){const isCase=n.kind==='case',isEntity=n.kind==='entity',selected=n.id===state.selected,dim=state.selected&&!active.has(n.id)&&!selected,r=(isCase?16:isEntity?10:8)*Math.max(.72,n.scale);ctx.save();ctx.globalAlpha=dim?.22:1;if(isCase){ctx.beginPath();ctx.arc(n.sx,n.sy,r+9,0,Math.PI*2);ctx.strokeStyle=n.color+'42';ctx.lineWidth=1;ctx.setLineDash([2,4]);ctx.stroke();ctx.setLineDash([])}const glow=ctx.createRadialGradient(n.sx,n.sy,0,n.sx,n.sy,r*3);glow.addColorStop(0,isCase?n.color+'78':isEntity?'#f07bc177':'#7fe7f292');glow.addColorStop(1,'transparent');ctx.fillStyle=glow;ctx.beginPath();ctx.arc(n.sx,n.sy,r*3,0,Math.PI*2);ctx.fill();ctx.beginPath();ctx.arc(n.sx,n.sy,r,0,Math.PI*2);ctx.fillStyle=isCase?'#0c151d':isEntity?'#211627':selected?'#d2fbfd':'#8edee7';ctx.fill();ctx.strokeStyle=isCase?n.color:isEntity?'#f07bc1':selected?'#fff':'#b9f4f8';ctx.lineWidth=isCase||isEntity?1.2:1;ctx.stroke();if(isCase||isEntity){ctx.beginPath();ctx.arc(n.sx,n.sy,r-(isCase?5:3),0,Math.PI*2);ctx.strokeStyle=(isCase?n.color:'#f07bc1')+'a0';ctx.stroke()}if(selected){ctx.beginPath();ctx.arc(n.sx,n.sy,r+7+Math.sin(Date.now()/300)*1.5,0,Math.PI*2);ctx.strokeStyle='rgba(127,231,242,.5)';ctx.stroke()}if(isCase||selected||state.hover===n.id||active.has(n.id)){ctx.font=`${isCase?'650':'500'} ${isCase?10:8}px Inter, sans-serif`;ctx.textAlign='center';ctx.fillStyle=dim?'#586471':'#dce5e9';ctx.shadowColor='#070a0f';ctx.shadowBlur=5;ctx.fillText(n.name,n.sx,n.sy+r+(isCase?19:14));ctx.shadowBlur=0}ctx.restore()}
function hit(x,y){return[...projected].reverse().find(n=>Math.hypot(x-n.sx,y-n.sy)<(n.kind==='case'?25:15))}

canvas.addEventListener('pointerdown',e=>{state.drag=true;state.startX=state.lastX=e.clientX;state.startY=state.lastY=e.clientY;canvas.setPointerCapture(e.pointerId)});
canvas.addEventListener('pointermove',e=>{const r=canvas.getBoundingClientRect(),x=e.clientX-r.left,y=e.clientY-r.top;if(state.drag){state.rotY+=(e.clientX-state.lastX)*.006;state.rotX+=(e.clientY-state.lastY)*.004;state.lastX=e.clientX;state.lastY=e.clientY;draw();return}const n=hit(x,y);state.hover=n?.id||null;canvas.style.cursor=n?'pointer':'grab';const card=document.querySelector('#hoverCard');if(n){card.hidden=false;card.style.left=(x+14)+'px';card.style.top=(y+12)+'px';card.innerHTML=`<strong>${n.name}</strong><span>${n.subtitle||n.role}</span>`}else card.hidden=true;draw()});
canvas.addEventListener('pointerup',e=>{const moved=Math.abs(e.clientX-state.startX)+Math.abs(e.clientY-state.startY);state.drag=false;if(moved<5){const r=canvas.getBoundingClientRect(),n=hit(e.clientX-r.left,e.clientY-r.top);if(n)selectNode(n.id)}});
canvas.addEventListener('pointerleave',()=>{state.drag=false;state.hover=null;document.querySelector('#hoverCard').hidden=true;draw()});
canvas.addEventListener('wheel',e=>{e.preventDefault();state.zoom=Math.max(.55,Math.min(2,state.zoom*(e.deltaY>0?.92:1.08)));draw()},{passive:false});

function syncUrl(id){try{const url=new URL(location.href);if(id)url.searchParams.set('node',id);else url.searchParams.delete('node');history.replaceState({},'',url)}catch{}}
function selectNode(id,{sync=true}={}){const n=nodes.find(x=>x.id===id);if(!n)return;if(n.kind==='case'){state.caseFocus=id;state.selected=id;document.querySelectorAll('.case-item').forEach(b=>b.classList.toggle('active',b.dataset.id===id));updateCaseDetail(n);if(sync)syncUrl(id);draw();return}state.caseFocus=null;state.selected=id;document.querySelectorAll('.case-item').forEach(b=>b.classList.remove('active'));updateDetail(n);if(sync)syncUrl(id);draw()}
function applyStatus(status){const labels={investigacion:'EN INVESTIGACIÓN',procesamiento:'PROCEDIMIENTO ABREVIADO',juicio:'JUICIO ABIERTO',revision:'EN REVISIÓN / NO FIRME',condena:'SENTENCIA FIRME',absuelto:'ABSUELTO',archivo:'ARCHIVADO / SOBRESEÍDO',mixto:'RESULTADOS MIXTOS POR PIEZA'},colors={investigacion:'var(--amber)',procesamiento:'#42c7aa',juicio:'var(--violet)',revision:'#6c8cff',condena:'var(--red)',absuelto:'#64d18f',archivo:'#8aa0b5',mixto:'#f1b658'},badge=document.querySelector('#statusBadge');badge.innerHTML=`<i></i> ${labels[status]}`;badge.style.color=colors[status]}
function renderSources(sources){document.querySelector('#sourceCount').textContent=sources.length;document.querySelector('#sources').innerHTML=sources.map(s=>`<div class="source-entry"><strong>${s.title}</strong><span>${s.date}</span><a href="${s.url}" target="_blank" rel="noreferrer">Abrir fuente ↗</a></div>`).join('')}
function classifyMoney(value,label){const text=`${value} ${label}`.toUpperCase();if(/^0(?:[,.]|\s|€)/.test(String(value).trim()))return'SIN RESPONSABILIDAD ECONÓMICA';if(/NO DETERMIN|NO ACREDIT|NO CONSOLID|POR PIEZA|^—/.test(text))return'NO SUMABLE / NO DETERMINADA';if(/MULTA/.test(text))return'MULTA PENAL';if(/COMISO|GANANCIAS|DÁDIVAS|EFECTIVO|SOBORNO|COMISIÓN/.test(text))return'DÁDIVA · GANANCIA · COMISO';if(/CONTRAT|SUBVENCIÓN|FLUJO/.test(text))return'VOLUMEN EXAMINADO';if(/PERJUICIO|FONDOS PÚBLICOS DESVIADOS/.test(text))return'PERJUICIO / FONDOS PÚBLICOS';return'CUANTÍA DOCUMENTADA'}
function applyMoney(value,label,note){document.querySelector('#moneyValue').textContent=value;document.querySelector('#moneyLabel').textContent=label;document.querySelector('#moneyNote').textContent=note;document.querySelector('#moneyKind').textContent=classifyMoney(value,label)}
function relationshipRows(actor){return actors.filter(other=>other.id!==actor.id&&other.caseIds.some(caseId=>actor.caseIds.includes(caseId))).map(other=>{const direct=links.find(link=>(link.a===actor.id&&link.b===other.id)||(link.b===actor.id&&link.a===other.id));const shared=actor.caseIds.filter(caseId=>other.caseIds.includes(caseId)).map(caseId=>cases.find(item=>item.id===caseId)?.name).filter(Boolean);return{actor:other,label:direct?.type||`Coincidencia procesal en ${shared.join(' y ')}`,direct:Boolean(direct)}}).sort((a,b)=>Number(b.direct)-Number(a.direct)||a.actor.name.localeCompare(b.actor.name,'es'))}
function updateDetail(p){document.querySelector('#relationSectionTitle').textContent='TRAMA VINCULADA';document.querySelector('#processSectionTitle').textContent='SITUACIÓN PROCESAL';document.querySelector('#moneySectionTitle').textContent='CUANTÍA ATRIBUIBLE';document.querySelector('#avatar').textContent=p.initials;document.querySelector('#personName').textContent=p.name;document.querySelector('#personRole').textContent=p.role;applyStatus(p.status);const linkedCases=p.caseIds.map(id=>cases.find(c=>c.id===id));document.querySelector('#linkedCases').innerHTML=linkedCases.map(c=>`<button class="linked-case" data-case="${c.id}"><span class="mini-orbit" style="color:${c.color};border-color:${c.color}55">◌</span><span><strong>${c.name}</strong><small>${c.subtitle}</small></span><b>›</b></button>`).join('');document.querySelectorAll('[data-case]').forEach(b=>b.onclick=()=>selectNode(b.dataset.case));document.querySelector('#chargeCard').innerHTML=`<span class="charge-icon">§</span><div><strong>${p.charge}</strong><p>${p.chargeNote}</p></div>`;applyMoney(p.money,p.moneyLabel,p.moneyNote);const related=relationshipRows(p);document.querySelector('#connectionCount').textContent=related.length;document.querySelector('#connections').innerHTML=related.length?related.map(({actor,label,direct})=>`<button class="connection ${direct?'direct':'shared'}" data-person="${actor.id}"><i>${actor.initials}</i><span><strong>${actor.name}</strong><small>${direct?'VÍNCULO DOCUMENTADO':'MISMA TRAMA'} · ${label}</small></span></button>`).join(''):'<p class="placeholder">No hay otros actores publicados en esta pieza.</p>';document.querySelectorAll('[data-person]').forEach(b=>b.onclick=()=>selectNode(b.dataset.person));renderSources(p.sources)}
function updateCaseDetail(c){const participants=actors.filter(actor=>actor.caseIds.includes(c.id));document.querySelector('#relationSectionTitle').textContent='ACTORES VINCULADOS';document.querySelector('#processSectionTitle').textContent='ESTADO DE LA TRAMA';document.querySelector('#moneySectionTitle').textContent='ALCANCE ECONÓMICO';document.querySelector('#avatar').textContent='◎';document.querySelector('#personName').textContent=c.name;document.querySelector('#personRole').textContent=c.subtitle;applyStatus(c.status);document.querySelector('#linkedCases').innerHTML=participants.map(p=>`<button class="linked-case" data-person="${p.id}"><span class="mini-orbit" style="color:${p.kind==='entity'?'#f07bc1':c.color};border-color:${p.kind==='entity'?'#f07bc155':c.color+'55'}">${p.initials}</span><span><strong>${p.name}</strong><small>${p.role}</small></span><b>›</b></button>`).join('');document.querySelector('#chargeCard').innerHTML=`<span class="charge-icon">§</span><div><strong>${c.phase}</strong><p>${c.phaseNote}</p></div>`;applyMoney(c.money,c.moneyLabel,c.moneyNote);document.querySelector('#connectionCount').textContent=participants.length;document.querySelector('#connections').innerHTML=participants.map(p=>`<button class="connection" data-person="${p.id}"><i>${p.initials}</i><span><strong>${p.name}</strong><small>${p.kind==='entity'?'ENTIDAD · ':''}${p.status.toUpperCase()}</small></span></button>`).join('');document.querySelectorAll('[data-person]').forEach(b=>b.onclick=()=>selectNode(b.dataset.person));renderSources(c.sources)}
function buildCases(){document.querySelector('#caseList').innerHTML=cases.map(c=>`<button class="case-item" data-id="${c.id}" style="--case-color:${c.color}"><span class="case-orbit">◌</span><span><strong>${c.name}</strong><small>${c.subtitle}</small></span><b>${c.count}</b></button>`).join('');document.querySelectorAll('.case-item').forEach(b=>b.onclick=()=>selectNode(b.dataset.id))}
function refreshCatalogMetrics(){document.querySelectorAll('.filter').forEach(button=>{const value=button.dataset.filter;button.querySelector('b').textContent=value==='all'?actors.length:actors.filter(actor=>actor.status===value).length});document.querySelector('#caseTotal').textContent=cases.length;document.querySelector('#peopleMetric').textContent=people.length;document.querySelector('#caseMetric').textContent=cases.length;document.querySelector('#linkMetric').textContent=links.length}
function buildTimeline(){const ordered=[...cases].sort((a,b)=>b.milestoneDate.localeCompare(a.milestoneDate));document.querySelector('#timelineView').innerHTML=`<div class="timeline-title"><div class="eyebrow">HITOS JUDICIALES VERIFICADOS</div><h2>La red a través del tiempo</h2><p>Cada fecha representa el último hito incorporado, no el inicio del caso.</p></div><div class="timeline-track">${ordered.map(c=>`<article class="timeline-entry" data-timeline-case="${c.id}" style="--event-color:${c.color}"><span class="timeline-year">${c.milestoneDate.slice(0,4)}</span><strong>${c.name}</strong><p>${c.milestone}</p><small>${c.milestoneDate.split('-').reverse().join(' · ')} · ${c.count} ACTOR${c.count===1?'':'ES'}</small></article>`).join('')}</div>`;document.querySelectorAll('[data-timeline-case]').forEach(entry=>entry.onclick=()=>{setView('network');selectNode(entry.dataset.timelineCase)})}
function setView(view){const timeline=view==='timeline';document.querySelector('#timelineView').hidden=!timeline;canvas.hidden=timeline;document.querySelector('.canvas-hint').hidden=timeline;document.querySelector('.legend').hidden=timeline;document.querySelector('.zoom-tools').hidden=timeline;document.querySelectorAll('.view-switch button').forEach(b=>b.classList.toggle('active',b.dataset.view===view));if(!timeline)resize()}

document.querySelectorAll('.filter').forEach(b=>b.onclick=()=>{state.filter=b.dataset.filter;state.caseFocus=null;document.querySelectorAll('.filter').forEach(x=>x.classList.toggle('active',x===b));document.querySelectorAll('.case-item').forEach(x=>x.classList.remove('active'));draw()});
document.querySelector('#clearFilters').onclick=()=>{state.filter='all';state.query='';state.caseFocus=null;document.querySelector('#searchInput').value='';document.querySelectorAll('.filter').forEach((x,i)=>x.classList.toggle('active',i===0));document.querySelectorAll('.case-item').forEach(x=>x.classList.remove('active'));draw()};
document.querySelector('#searchInput').addEventListener('input',e=>{state.query=e.target.value.trim().toLowerCase();draw()});
document.addEventListener('keydown',e=>{if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='k'){e.preventDefault();document.querySelector('#searchInput').focus()}if(e.key==='Escape'){document.querySelector('#modal').hidden=true;document.querySelector('#coverageModal').hidden=true}});
document.querySelector('#zoomIn').onclick=()=>{state.zoom=Math.min(2,state.zoom*1.16);draw()};document.querySelector('#zoomOut').onclick=()=>{state.zoom=Math.max(.55,state.zoom/1.16);draw()};document.querySelector('#resetView').onclick=()=>{state.rotX=-.08;state.rotY=.08;state.zoom=1;state.caseFocus=null;draw()};
document.querySelectorAll('.detail-tabs button').forEach(b=>b.onclick=()=>{document.querySelectorAll('.detail-tabs button').forEach(x=>x.classList.toggle('active',x===b));document.querySelectorAll('.tab-content').forEach(x=>x.classList.toggle('active',x.id===`tab-${b.dataset.tab}`))});
document.querySelectorAll('.view-switch button').forEach(b=>b.onclick=()=>setView(b.dataset.view));
const modal=document.querySelector('#modal');document.querySelector('#aboutButton').onclick=()=>modal.hidden=false;document.querySelector('#modalClose').onclick=()=>modal.hidden=true;modal.onclick=e=>{if(e.target===modal)modal.hidden=true};
const coverageModal=document.querySelector('#coverageModal');document.querySelector('#coverageButton').onclick=()=>coverageModal.hidden=false;document.querySelector('#coverageClose').onclick=()=>coverageModal.hidden=true;coverageModal.onclick=e=>{if(e.target===coverageModal)coverageModal.hidden=true};
document.querySelector('#shareButton').onclick=async()=>{const url=location.href;try{await navigator.clipboard.writeText(url);const b=document.querySelector('#shareButton');b.innerHTML='<span>✓</span> Enlace copiado';setTimeout(()=>b.innerHTML='<span>↗</span> Compartir vista',1600)}catch{prompt('Copia este enlace para conservar la selección:',url)}};
document.querySelector('#closeDetail').onclick=()=>{state.selected=null;state.caseFocus=null;syncUrl(null);document.querySelectorAll('.case-item').forEach(b=>b.classList.remove('active'));draw()};
buildCases();buildTimeline();refreshCatalogMetrics();document.querySelector('#coverageCases').textContent=cases.length;document.querySelector('#coverageActors').textContent=actors.length;const requestedNode=new URL(location.href).searchParams.get('node');if(requestedNode&&nodes.some(node=>node.id===requestedNode))selectNode(requestedNode,{sync:false});else updateDetail(people[0]);window.addEventListener('resize',resize);resize();
function animate(){draw();requestAnimationFrame(animate)}requestAnimationFrame(animate);
